query:
{
  statefulSets(
    where: {
      podTemplate: {
        securityContext: {
          OR: [
            { supplementalGroups: { eq: [] } }
            { isSysctlsContainingElements: { eq: false } }
            { isSeccompProfileSet: { eq: false } }
            { isFSGroupChangePolicySet: { eq: false } }
            { isFSGroupSet: { eq: false } }
            {
              NOT: {
                OR: [
                  {
                    isFSGroupChangePolicySet: { eq: true }
                    fsGroupChangePolicy_CONTAINS: "Always"
                  }
                  {
                    isFSGroupChangePolicySet: { eq: true }
                    fsGroupChangePolicy_CONTAINS: "OnRootMismatch"
                  }
                ]
              }
            }
            { AND: [{ isFSGroupSet: { eq: true } }, { fsGroup_LTE: 0 }] }
          ]
        }
      }
    }
  ) {
    ...AssetFragment
  }
}
